  // js/features/payload.js
  function decodeEncryptedPayload(encoded) {
    const raw = atob(String(encoded || "").trim());
    const legacyPlaintext = xorCrypt(raw);
    let utf8Plaintext = "";
    try {
      const utf8Encrypted = decodeURIComponent(escape(raw));
      utf8Plaintext = xorCrypt(utf8Encrypted);
    } catch (_) {
    }
    return {
      legacyPlaintext,
      utf8Plaintext,
      preferred: utf8Plaintext || legacyPlaintext
    };
  }
  function decodeDatabasePayload(encoded) {
    const decoded = decodeEncryptedPayload(encoded);
    if (decoded.legacyPlaintext.includes(":") && decoded.legacyPlaintext.includes("|")) return decoded.legacyPlaintext;
    if (decoded.utf8Plaintext.includes(":") && decoded.utf8Plaintext.includes("|")) return decoded.utf8Plaintext;
    if (parseMarkdownDatabase(decoded.utf8Plaintext).entries.length) return decoded.utf8Plaintext;
    if (parseMarkdownDatabase(decoded.legacyPlaintext).entries.length) return decoded.legacyPlaintext;
    return decoded.preferred;
  }
  function decodeStatusPayload(encoded) {
    const decoded = decodeEncryptedPayload(encoded);
    const candidates = [decoded.utf8Plaintext, decoded.legacyPlaintext].filter(Boolean);
    return candidates.find((content) => parseStatusProfile(content).loaded) || decoded.preferred;
  }

  // js/terminal/progress.js
  var SPINNER = ["/", "-", "\\", "|"];
  async function runTerminalProgressBar(options = {}) {
    renderTranscriptInstantFromBuffer();
    const heading = String(options.heading || "").trim();
    const label = String(options.label || "TERMINAL BUS").trim().toUpperCase();
    const width = Math.max(8, Number.parseInt(options.width, 10) || (window.innerWidth < 520 ? 18 : 28));
    const duration = Math.max(1, motion.reduced ? Math.min(Number(options.duration) || 520, 520) : Number(options.duration) || 1600);
    appendMutableOutputLine("", "");
    if (heading) appendMutableOutputLine(heading, options.headingClass || "t-cyan");
    const row = appendMutableOutputLine(`${SPINNER[0]} ${label} [${"-".repeat(width)}] 000%`, options.className || "t-amber");
    const start = performance.now();
    let lastTick = 0;
    await new Promise((resolve) => {
      function frame(now = performance.now()) {
        const elapsed = Math.max(0, Math.min(duration, now - start));
        const progress = elapsed / duration;
        const filled = Math.min(width, Math.floor(progress * width));
        const bar = `${"#".repeat(filled)}${"-".repeat(width - filled)}`;
        const percent = String(Math.floor(progress * 100)).padStart(3, "0");
        const glyph = SPINNER[Math.floor(elapsed / 120) % SPINNER.length];
        row.update(`${glyph} ${label} [${bar}] ${percent}%`, progress >= 1 ? options.doneClassName || "t-cyan" : options.className || "t-amber");
        if (now - lastTick > 620) {
          lastTick = now;
          AudioEngine.keyClick();
        }
        if (progress >= 1) {
          row.update(`> ${label} [${"#".repeat(width)}] OK`, options.doneClassName || "t-cyan");
          if (options.successTone !== false) AudioEngine.successTone();
          resolve();
          return;
        }
        requestAnimationFrame(frame);
      }
      requestAnimationFrame(frame);
    });
    return appendMutableOutputLine;
  }
  async function bootStyleStep(text, options = {}) {
    const className = options.className || "t-dim";
    const doneClass = options.doneClassName || "t-cyan";
    const tag = options.tag || "OK";
    const spinMs = motion.reduced ? 80 : options.spinMs ?? 320;
    const settleMs = motion.reduced ? 0 : options.settleMs ?? 70;
    const row = appendMutableOutputLine(`${text} [/]`, className);
    const start = performance.now();
    let lastClick = 0;
    await new Promise((resolve) => {
      function tick(now = performance.now()) {
        const elapsed = now - start;
        if (elapsed >= spinMs) {
          row.update(`${text} [ ${tag} ]`, doneClass);
          resolve();
          return;
        }
        row.update(`${text} [${SPINNER[Math.floor(elapsed / 95) % SPINNER.length]}]`, className);
        if (now - lastClick > 240) {
          lastClick = now;
          AudioEngine.keyClick();
        }
        requestAnimationFrame(tick);
      }
      requestAnimationFrame(tick);
    });
    if (settleMs > 0) await new Promise((r) => setTimeout(r, settleMs));
  }
  async function bootStyleHeader(text, className = "t-amber") {
    appendMutableOutputLine(text, className);
    if (!motion.reduced) await new Promise((r) => setTimeout(r, 90));
  }

